// Dicionário de Nomes dos Vendedores
const OWNER_MAP = {
  '86857769': 'Isaque Inacio',
  '85822345': 'Luan Silva',
  '1856577327': 'Rodrigo Fernandes',
  '69864695': 'Rodrigo Fernandes',
  '2011790555': 'Rodrigo Fernandes',
  '78938498': 'Leonardo Padilha',
  '86362284': 'Leonardo Souza',
  '85369712': 'Joel Carlos'
};

// Fases que queremos na tabela do Closer
const FOLLOW_UP_STAGES = [
  '1225098151', // Negociação
  '1225024929', // Assinatura de Contrato
  '1225098152'  // Vendido
];

let inputDeals = items[0].json.results ? items[0].json.results : items.map(i => i.json);
let activeDeals = [];

for (const deal of inputDeals) {
    const props = deal.properties || deal;

    // Se o deal estiver em uma das fases de fechamento
    if (FOLLOW_UP_STAGES.includes(props.dealstage)) {
        activeDeals.push({
            json: {
                deal_id: deal.id,
                deal_name: props.dealname || 'Negócio sem nome',
                owner_id: OWNER_MAP[props.hubspot_owner_id] || props.hubspot_owner_id || 'Sem Dono',
                stage_id: props.dealstage,
                amount: parseFloat(props.amount) || 0,
                created_date: (props.createdate || new Date().toISOString()).split('T')[0]
            }
        });
    }
}

return activeDeals;
